    process: processHandle,
    startedAtMs: Date.now(),
    killRequested: false,
    killReason: ''
  };
  activeChatRuns.set(key, activeRun);
  return activeRun;
}

function clearActiveChatRun(activeRun) {
  if (!activeRun) return;
